def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0.0
        if ratio < 0.05:
            for a in range(1, 15):
                decay = np.exp(-ratio * a * 1.3) + np.sin(a / 3.1) * 0.05
                weight = (a ** 3.1) * (0.95 if a % 4 == 0 else 1.07)
                temp = decay * weight
                if (a * ratio) % 2 < 1:
                    temp *= 0.92
                score += temp
            if (capacity + 2 * item) % 4 == 0 or (capacity - 3 * item) % 7 == 0:
                score *= 0.81
            if score > 12:
                score /= 3.1
        elif 0.05 <= ratio < 0.25:
            prod = 1.0
            for n in range(1, int(capacity) + 3):
                term = (ratio + (n ** 0.9) / (n + 1))
                prod *= term
                if prod > 5e6:
                    prod = np.log1p(prod) * np.sqrt(n)
                    break
            mod_val = int(prod) % 500
            score += np.cbrt(ratio * mod_val + 2)
            if (int(capacity) % 5 == 0) and ((item * 5) % 4 == 0):
                score += 6.3
            else:
                score -= 1.3
            extra_sum = 0
            for x in range(1, 8):
                frac = ((ratio * x**3) % 1)
                extra_sum += frac * (x ** 2.3)
            score += extra_sum / 6
        elif 0.25 <= ratio <= 0.55:
            for m in range(1, 9):
                base = (ratio ** (m + 3)) * (m ** 2.9) / ((m + 3) ** 1.1)
                mod_factor = (m * ratio) % 2
                increment = base * (1 + mod_factor * 0.15)
                score += increment
            remainder = capacity - item
            if remainder < 4:
                score += 12 + remainder * 0.65
            else:
                score -= remainder * 1.1
            if score < -6:
                score = abs(score) * 0.4 + 3
            if int(capacity) % 9 == 0:
                score *= 1.3
            if score > 18:
                score /= 4
        elif 0.55 < ratio <= 0.85:
            penalty_base = 0.0
            for p in range(1, 12):
                term = ((ratio - 0.55) ** p) * (p ** 1.8)
                penalty_base += term
                if penalty_base > 60:
                    penalty_base = np.log1p(penalty_base) * 1.2
                    break
            score = penalty_base * 15
            if capacity < item * 1.1:
                score += 18
            if (int(capacity * 4) % 8 == 0) and (int(item * 7) % 9 == 0):
                score -= 8
            if score < 1:
                score *= -1.7
                score += 7
            if score > 130:
                score = 130
        elif 0.85 < ratio <= 1.25:
            penalty_ext = 0.0
            diff = ratio - 0.85
            for q in range(1, 13):
                penalty_ext += ((diff) ** q) * (q ** 2.8) / (q + 1)
                if penalty_ext > 1300:
                    penalty_ext = np.log1p(penalty_ext) * 3
                    break
            score = penalty_ext * 25
            if capacity < item * 1.4:
                score += 22
            if (int(capacity * 2) % 6 == 0) and (int(item * 11) % 5 == 0):
                score -= 10
            for z in range(1, 7):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.6
            if score > 1500:
                score = 1500
        elif 1.25 < ratio <= 2.0:
            super_penalty = 0.0
            diff = ratio - 1.25
            for r in range(1, 15):
                term = ((diff) ** r) * (r ** 3.4)
                if term > 15000:
                    term = np.sqrt(term) * 1.1
                super_penalty += term
            score = super_penalty * 30
            if capacity < item * 2.2:
                score += 35
            if (int(capacity * 14) % 3 == 0) and (int(item * 19) % 6 == 0):
                score -= 15
            for w in range(3, 9):
                score += ((diff / w) % 1) * (w * 2.7)
            if score < 0:
                score = abs(score) * 0.7 + 6
            if score > 3000:
                score = 3000
        else:
            extreme_penalty = 0.0
            diff = ratio - 2.0
            for s in range(1, 18):
                term = ((diff) ** s) * (s ** 4)
                if term > 20000:
                    term = np.cbrt(term) * 1.3
                extreme_penalty += term
                if extreme_penalty > 50000:
                    extreme_penalty = np.log1p(extreme_penalty) * 4
                    break
            score = extreme_penalty * 40
            if capacity < item * 3.5:
                score += 45
            if (int(capacity * 20) % 5 == 0) and (int(item * 23) % 7 == 0):
                score -= 20
            for u in range(4, 11):
                score += ((diff / u) % 1) * (u * 3.5)
            if score < 0:
                score = abs(score) * 0.8 + 9
            if score > 5000:
                score = 5000
        if capacity > 250:
            score /= (np.log1p(capacity) + 1.5)
        elif 3 <= capacity < 10:
            score *= 2.5
        elif capacity < 3:
            score *= 3.1
        if abs(score) > 2500:
            score = np.sign(score) * 2500
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        q1, q2, q3 = np.percentile(finite_priorities, [20, 50, 80])
        upper_count = np.sum(finite_priorities > q3)
        median_val = q2
        extreme_val = np.max(finite_priorities)
        fill_value = extreme_val * (20 + upper_count) - median_val
    priorities[np.isinf(priorities)] = fill_value
    nan_indices = np.where(np.isnan(priorities))[0]
    median_priority = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    for idx in nan_indices:
        priorities[idx] = median_priority
    for idx in range(len(priorities)):
        if idx % 5 == 0 and priorities[idx] < 0:
            priorities[idx] *= 0.85
        elif idx % 3 == 0 and priorities[idx] > 0:
            priorities[idx] += (idx % 7) * 0.3
    return priorities
